const item = $("Loop Over Items").first().json
const status = !item.teamsId ? 'MISMATCH_TEAMS' : 'NOTIFY_DISABLED';
const detail = !item.teamsId
  ? 'No se encontró teamsId para este email en dbo.NotiViga_userInfo'
  : 'Usuario tiene notify=0 en la base de datos';
return [{ json: { ...item, status: status, errorDetail: detail }}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

let totalSuccess = 0, totalErrors = 0;
try {
  const brainItems = $('The Brain v1').all();
  totalSuccess = brainItems.filter(i => i.json._status === 'SUCCESS').length;
  totalErrors  = brainItems.filter(i => i.json._status !== 'SUCCESS').length;
} catch(e) {}
const totalProcessed = totalSuccess + totalErrors;
const status = totalErrors === 0 ? 'SUCCESS' : (totalSuccess === 0 ? 'ERROR' : 'PARTIAL');
return [{ json: {
  executionId: $execution.id,
  totalNotified: totalSuccess,
  totalProcessed,
  totalSuccess,
  totalErrors,
  status
}}];

// Nodo central: normaliza todos los paths en un registro unificado
const item = $input.first().json;

// Función para Strings: Si es nulo/vacío devuelve NULL (palabra clave), si no, escapa y pone comillas
const escSQL = v => {
    if (v === null || v === undefined || v === '') return 'NULL';
    const clean = String(v).replace(/'/g, "''").slice(0, 500);
    return `'${clean}'`;
};

// Función para Números: Si no es un número válido, devuelve NULL (palabra clave)
const numSQL = v => {
    const parsed = parseFloat(v);
    return isNaN(parsed) ? 'NULL' : parsed;
};

const eId    = $execution.id;
const name   = escSQL(item.fullName);
const email  = escSQL(item.email);
const expH   = numSQL(item.expectedHours);
const totH   = numSQL(item.totalHours);
const pct    = numSQL(item.completionPercentage);
const status = escSQL(item.status || 'UNKNOWN');
const detail = escSQL(item.errorDetail); // Ya no forzamos ''
const notifiedAt = escSQL(item.notifiedAt);

// Nota: Quitamos las comillas fijas de los valores que ya vienen procesados por escSQL y numSQL
const sql = `INSERT INTO dbo.NotiViga_notification_logs 
(executionId, fullName, email, expectedHours, totalHours, completionPercentage, status, errorDetail, notifiedAt)
VALUES 
('${eId}', ${name}, ${email}, ${expH}, ${totH}, ${pct}, ${status}, ${detail}, ${notifiedAt})`;

return [{ json: { ...item, _sql: sql } }];
